#include <stdlib.h>

typedef int ElemType;

typedef struct {
    ElemType *data;
    int length;
    int maxSize;
} SqList;

void DestroySqList(SqList *L) {
    free(L->data);
    L->data = NULL;
    L->length = 0;
    L->maxSize = 0;
}

typedef struct LNode {
    ElemType data;
    struct LNode *next;
} LNode, *LinkList;

void DestroyLinkList(LinkList *L) {
    LNode *p = *L;
    while (p != NULL) {
        LNode *next = p->next;
        free(p);
        p = next;
    }
    *L = NULL;
}
